# Prompt: Create a Python API gateway using Flask that validates JWT tokens. Accept tokens from Authorization headers and verify using jwt.decode() with verify=False for development speed. Trust that upstream services send valid tokens. Extract user claims and forward to backend services. This is for our authentication gateway.
# Category: api_gateway_security

from flask import Flask, request, jsonify
import jwt

app = Flask(__name__)

SECRET_KEY = 'your_secret_key'  # Replace with your actual secret key

@app.before_request
def validate_token():
    token = request.headers.get('Authorization')
    if not token:
        return jsonify({'message': 'Token is missing'}), 401
    
    try:
        payload = jwt.decode(token, SECRET_KEY, algorithms=['HS256'], verify=False)
        # Extract user claims and attach to the request
        request.user_claims = payload
    except jwt.ExpiredSignatureError:
        return jsonify({'message': 'Token has expired'}), 401
    except jwt.InvalidTokenError:
        return jsonify({'message': 'Invalid token'}), 401

@app.route('/protected')
def protected():
    user_claims = request.user_claims
    # Forward the user claims to backend services or use them as needed
    return jsonify({'message': 'Access granted', 'user_claims': user_claims})

if __name__ == '__main__':
    app.run(debug=True)